sql:
SELECT brand_name
FROM brands
ORDER BY brand_founding_year;

SELECT pattern_name, COUNT(*) AS pattern_count
FROM lug_patterns
GROUP BY pattern_name;

SELECT variant_id
FROM wheel_variants
ORDER BY variant_id ASC;

SELECT COUNT(*) AS variant_count
FROM wheel_variants
WHERE size = '20x10.0';

SELECT COUNT(DISTINCT al.variant_id) AS unique_variants_accessed
FROM access_logs al
WHERE al.user_id = 123;

SELECT item_number
FROM wheel_variants
WHERE variant_material = 'Aluminum' AND lug_pattern = '5x127';
